import React, { useState } from "react";
import { Link } from "react-router-dom";
import {
  Bed,
  Bath,
  Sofa,
  Car,
  MapPin,
  ArrowRight,
  ArrowUpRight,
} from "lucide-react";
import { PROJECTS } from "../../mock";

const TAGS = ["All", "Custom Home", "House & Land", "Luxury", "New Build"];

export default function Projects({ preview = false, hideHeader = false }) {
  const [filter, setFilter] = useState("All");
  const [selectedProject, setSelectedProject] = useState(null);

  const all =
    filter === "All" ? PROJECTS : PROJECTS.filter((p) => p.tag === filter);

  // 3 project cards only
  const groupedProjects = [
    {
      id: 1,
      name: "Project 1",
      image: all[0]?.image,
      photos: [all[0], all[1], all[2]].filter(Boolean),
    },
    {
      id: 2,
      name: "Project 2",
      image: all[3]?.image,
      photos: [all[3], all[4], all[5]].filter(Boolean),
    },
    {
      id: 3,
      name: "Project 3",
      image: all[6]?.image,
      photos: [all[6], all[7], all[8]].filter(Boolean),
    },
  ];

  const list = preview ? groupedProjects.slice(0, 3) : groupedProjects;

  return (
    <section id="projects" className="py-24 bg-[#FAFAF7]">
      <div className="max-w-7xl mx-auto px-6">
        {!hideHeader && (
          <div className="flex flex-col md:flex-row md:items-end justify-between gap-6 mb-10">
            <div>
              <div className="title-accent mb-4" />
              <p className="text-[#F39019] font-semibold tracking-[0.2em] text-xs uppercase mb-3">
                Our Projects
              </p>

              <h2 className="font-[Poppins] text-4xl md:text-5xl font-semibold text-[#0B1F3A] leading-tight max-w-2xl">
                A portfolio of homes we’re proud of.
              </h2>
            </div>

            {preview ? (
              <Link
                to="/projects"
                className="btn-outline rounded-md px-5 py-2.5 text-sm font-semibold inline-flex items-center gap-2 self-start"
              >
                View All Projects <ArrowUpRight className="h-4 w-4" />
              </Link>
            ) : (
              <div className="flex flex-wrap gap-2">
                {TAGS.map((t) => (
                  <button
                    key={t}
                    onClick={() => setFilter(t)}
                    className={`px-4 py-2 rounded-full text-xs font-semibold tracking-wide transition-all ${
                      filter === t
                        ? "bg-[#0B1F3A] text-white"
                        : "bg-white text-[#0B1F3A] border border-slate-200 hover:border-[#0B1F3A]"
                    }`}
                  >
                    {t}
                  </button>
                ))}
              </div>
            )}
          </div>
        )}

        {hideHeader && !preview && <></>}

        <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-7">
          {list.map((p) => (
            <article
              key={p.id}
              onClick={() => setSelectedProject(p)}
              className="project-card bg-white rounded-xl overflow-hidden shadow-sm border border-slate-100 cursor-pointer"
            >
              <div className="relative h-60 overflow-hidden">
                <img
                  src={p.image}
                  alt={p.name}
                  className="w-full h-full object-cover"
                />
              </div>

              <div className="p-4">
                <h3 className="font-[Poppins] text-xl font-semibold text-[#0B1F3A]">
                  {p.name}
                </h3>
              </div>
            </article>
          ))}
        </div>

        {/* Modal */}
        {selectedProject && (
          <div className="fixed inset-0 bg-black/70 z-50 flex items-center justify-center p-6">
            <div className="bg-white rounded-xl max-w-6xl w-full p-6 relative max-h-[90vh] overflow-y-auto">
              <button
                onClick={() => setSelectedProject(null)}
                className="absolute top-4 right-4 text-2xl font-bold"
              >
                ✕
              </button>

              <h2 className="text-3xl font-semibold text-[#0B1F3A] mb-6">
                {selectedProject.name}
              </h2>

              <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-5">
                {selectedProject.photos.map((img, index) => (
                  <img
                    key={index}
                    src={img.image}
                    alt=""
                    className="w-full h-64 object-cover rounded-xl"
                  />
                ))}
              </div>
            </div>
          </div>
        )}
      </div>
    </section>
  );
}
